      program   KennetSlo*     *****************************************************************     calculate the plane wave response of a plane stratified oceanic*     crust to a point explosion of pressure in the ocean layer using*     the Kennet Addition Formulae*     ****************************************************************	  INTEGER   OUTFILE,NLP1MAX,NWMAX,NPMAX	  parameter (outfile=11,NLP1MAX=5,NWMAX=2048,NPMAX=1)      COMPLEX   Ci,C0,C1,W0	  PARAMETER (Ci=(0.0,1.0),C1=(1.0,0.0),C0=(0.0,0.0))      COMPLEX   A(NLP1MAX),B(NLP1MAX),BETA(NLP1MAX)      COMPLEX   W,DW,ETA(NLP1MAX),NETA(NLP1MAX)      COMPLEX   CMPLXSLO,VERTICALSLO      COMPLEX   U(NWMAX,NPMAX),Uwk(2*NWMAX),M(NWMAX),S	  complex   Rd11(nlp1max),Rd12(nlp1max),Rd21(nlp1max),Rd22(nlp1max)	  complex   Tu11(nlp1max),Tu12(nlp1max),Tu21(nlp1max),Tu22(nlp1max)	  complex   Td11(nlp1max),Td12(nlp1max),Td21(nlp1max),Td22(nlp1max)	  complex   Ru11(nlp1max),Ru12(nlp1max),Ru21(nlp1max),Ru22(nlp1max)	  complex   ea(nlp1max),eb(nlp1max),eaeb(nlp1max),incea(nlp1max)	  complex   eaea(nlp1max),ebeb(nlp1max),inceaea(nlp1max),incebeb(nlp1max)      complex   inceaeb(nlp1max),inceb(nlp1max),PdPu,PdSd,SuPu,PdPd,PuPu	  REAL      p,pvec(Npmax),CA0(NLP1MAX),CB0(NLP1MAX),DD(NLP1MAX)	  REAL      QA0(NLP1MAX),QB0(NLP1MAX),H(NLP1MAX),RHO(NLP1MAX),T,DT	  character *1 TAB	  TAB=char(9)	  open(outfile,file='KennetSloGraphDat',status='new')	  !**********************************************************************!     INPUT THE EXPERIMENTAL GEOMETRY!**********************************************************************      DR=0.0      DS=DR	  !********************************************************************!     INPUT LAYER PARAMETERS!********************************************************************      NLP1=4	  IF(NLP1 .GT. NLP1MAX) THEN	    PAUSE 'TOO MANY LAYERS'	  END IF	  CA0(1)=1.5	  CB0(1)=0.0	  QA0(1)=2E04	  QB0(1)=1E10	  RHO(1)=1.0	  H(1)  =2.0	  DD(1) =H(1)-0.5*(Ds+Dr)	  CA0(2)=1.6	  CB0(2)=0.3	  QA0(2)=100	  QB0(2)=100	  RHO(2)=2.0*	  H(2)  =H(1)+512*ca0(2)	  H(2)  =H(1)+1.0	  DD(2) =H(2)-H(1)	  CA0(3)=3.0	  CB0(3)=1.5	  QA0(3)=100	  QB0(3)=100	  RHO(3)=3.0*	  H(3)  =H(2)+512*ca0(3)	  H(3)  =H(2)+1.0	  DD(3)=H(3)-H(2)	  CA0(4)=5.0	  CB0(4)=3.0	  QA0(4)=100	  QB0(4)=100	  RHO(4)=3.0	  H(4)  =H(3)+1.0	  DD(4)=H(4)-H(3)	  CA0(5)=2.2	  CB0(5)=1.1	  QA0(5)=100	  QB0(5)=100	  RHO(5)=1.8	  H(5)  =1E20*     *****************************************************************     Input the Slowness Vector*     ****************************************************************      type*,'Input the number of slownesses '	  Accept*,Np	  Do 10 ip=1,Np	    Type*,'input pvec(',ip,')'		Accept*,pvec(ip) 10	  continue*     Input Length of time series and number of frequencies      T=64      NW=2048*     Define miscellaneous program constants      NT=2*NW      DT=T/FLOAT(NT)      TPI=2.0*PI	        PI2=PI/2.      PI4=PI/4.      DW=TPI/T	  WMAX=NW*DW      NWM=NW-1*     define frequency damping factor*      eps=log(2.0)/T      eps=0.0*     max frequency index NW corresponds to frequency limit of source	        FMAX=FLOAT(NWM)/T*     define starting frequency (could have small pos. imag part)	        W0=cmplx(0.0,eps)	  *     *****************************************************************     input  source spectrum vector*     ****************************************************************      w=W0      Do 20 iw=1,Nwm	    w=w+Dw	    M(iw)=S(w,wmax) 20   continue*     *****************************************************************     define complex frequency independent slownesses of each layer*     ****************************************************************      A(1)=CMPLXSLO(CA0(1),QA0(1))	  B(1)=C0	  BETA(1)=C0      Do 30 IL=2,NLP1        A(IL)=CMPLXSLO(CA0(IL),QA0(IL))		B(IL)=CMPLXSLO(CB0(IL),QB0(IL))*		TYPE *,'A(IL),B(IL)=',A(IL),B(IL)*		PAUSE	    BETA(IL)=C1/B(IL) 30   continue	        Do 40 ip=1,Np*     ******************************************************************     compute the plane wave respone of the medium for each slowness*     *****************************************************************	   CALL SLOWRESP(Pvec,ip,np,W0,Nw,Dw,ea,eb,eaeb,NLP1,     &	            U,Nwmax,Nlp1max,A,B,BETA,RHO,DD,Rd11,Rd12,Rd21,Rd22,     &              Tu11,Tu12,Tu21,Tu22,Ru11,Ru12,Ru21,Ru22,Td11,Td12,     &              Td21,Td22,eta,neta,incea,inceb,inceaeb,     &              eaea,ebeb,inceaea,incebeb)*     multiply the the slowness response by the source spectrum vector      Do 50 iw=1,NWM       U(iw,ip)=U(iw,ip)*M(iw)*      U(iw,ip)=M(iw) 50   continue     *     Inverse FFT transfer function to give R(Tau,p) response      Do 60 iw=1,NWM        Uwk(iw+1)=U(iw,ip)        Uwk(NT-iw+1)=CONJG(U(iw,ip)) 60   continue      Uwk(1)=C0      Uwk(NW+1)=C0      CALL FFT(Uwk,NT,-1.0)	  TT=-Dt      Do 70 it=1,NT	    TT=TT+Dt*       compensate for the frequency damping and write to plotting file        ff=Real(Uwk(it))*exp(eps*TT)	    WRITE (outfile,999) TT,TAB,ff		TYPE*,TT,TAB,ff  70  continue*     ******************************************************************     End Slowness Loop*     ***************************************************************** 40   continue 999  FORMAT(f5.1,A1,g10.4)       close(outfile)      STOP      END      SUBROUTINE SLOWRESP(pvec,ip,np,W0,Nw,Dw,ea,eb,eaeb,NLP1,U,Nwmax,     &                    Nlp1max,A,B,BETA,RHO,DD,Rd11,Rd12,Rd21,Rd22,     &                    Tu11,Tu12,Tu21,Tu22,Ru11,Ru12,Ru21,Ru22,Td11,     &                    Td12,Td21,Td22,eta,neta,incea,inceb,inceaeb,     &                    eaea,ebeb,inceaea,incebeb)	  !**********************************************************************!     CALCULATE THE HORIZONTEL SLOWNESS DEPENDENT COMPONENTS OF THE!     REFLECTIVITY INTEGRAND!***********************************************************************	  Implicit none	  COMPLEX Ci,C1,C0	  	  PARAMETER (Ci=(0.0,1.0),C1=(1.0,0.0),C0=(0.0,0.0))      INTEGER NLP1,IL,Nw,Nl,Nwmax,ip,np,NLP1MAX      COMPLEX W0,Dw,A(NLP1MAX),B(NLP1MAX),BETA(NLP1MAX)	  COMPLEX ETA(NLP1max),NETA(NLP1max),U(Nwmax,np),cp	  complex Rd11(nlp1max),Rd12(nlp1max),Rd21(nlp1max),Rd22(nlp1max)	  complex Tu11(nlp1max),Tu12(nlp1max),Tu21(nlp1max),Tu22(nlp1max)	  complex Td11(nlp1max),Td12(nlp1max),Td21(nlp1max),Td22(nlp1max)	  complex Ru11(nlp1max),Ru12(nlp1max),Ru21(nlp1max),Ru22(nlp1max)	  complex ea(nlp1max),eb(nlp1max),eaeb(nlp1max),incea(nlp1max)	  complex eaea(nlp1max),ebeb(nlp1max),incebeb(nlp1max),inceaea(nlp1max)	  complex inceb(nlp1max),inceaeb(nlp1max),twomup	  REAL    RHO(NLP1max),DD(NLP1max),p,pvec(np)	  *     Initialise frequency independent layer parameters      p=pvec(ip)	  cp=cmplx(p)      Nl=Nlp1-1	  IL=1      NETA(IL)=C0	  ETA(IL)=VERTICALSLO(A(IL),CP)	  ea(1)=cexp(Ci*W0*DD(1)*eta(1))	  incea(1)=cexp(Ci*Dw*DD(1)*eta(1))	  eaea(1)=ea(1)*ea(1)	  inceaea(1)=incea(1)*incea(1)	  eb(1)=C0	  inceb(1)=C0	  eaeb(1)=C0	  inceaeb(1)=C0      DO IL=2,NL	    ETA(IL)=VERTICALSLO(A(IL),CP)		NETA(IL)=VERTICALSLO(B(IL),CP)        ea(il)=cexp(Ci*W0*eta(il)*DD(il))		eb(il)=cexp(Ci*W0*neta(il)*DD(il))		eaea(il)=ea(il)*ea(il)		ebeb(il)=eb(il)*eb(il)		eaeb(il)=ea(il)*eb(il)		incea(il)=cexp(Ci*Dw*eta(il)*DD(il))		inceb(il)=cexp(Ci*Dw*neta(il)*DD(il))		inceaea(il)=incea(il)*incea(il)		incebeb(il)=inceb(il)*inceb(il)		inceaeb(il)=incea(il)*inceb(il)	  END DO	  ETA(Nlp1)=VERTICALSLO(A(Nlp1),CP)	  NETA(Nlp1)=VERTICALSLO(B(Nlp1),CP)*     ********************************************************************     calculate the interfacial scattering coefficients of the layerstack*     *******************************************************************      call OBSMat(p,eta(1),rho(1),eta(2),neta(2),rho(2),beta(2),Rd11(1),     &     Td11(1),Td21(1),Tu11(1),Ru11(1),Ru21(1),Tu12(1),Ru12(1),Ru22(1))*     Calculate the Interfacial Scattering Coefficients	  Do il=2,nl	    ilp1=il+1	    call ScatMat(p,eta(il),neta(il),rho(il),beta(il),eta(ilp1),     &  neta(ilp1),rho(ilp1),beta(ilp1),Rd11(il),Rd12(il),Rd21(il),     &  Rd22(il),Tu11(il),Tu12(il),Tu21(il),Tu22(il),Td11(il),Td12(il),     &  Td21(il),Td22(il),Ru11(il),Ru12(il),Ru21(il),Ru22(il))	  End Do  *     CALCULATE THE OCEAN CRUST REFLECTIVITY (phase related to Ds)      call Kennet_Reflex(nlp1,Nw,Rd11,Rd12,Rd21,Rd22,Tu11,Tu12,Tu21,Tu22,     &           Ru11,Ru12,Ru21,Ru22,Td11,Td12,Td21,Td22,inceaea,incebeb,     &           inceaeb,eaea,ebeb,eaeb,ea,eb,incea,inceb,U(1,ip))*     Multiply the reflectivity by the source directivity      RETURN      END	  	  	  COMPLEX FUNCTION CMPLXSLO(C,Q)*     *************************************************************     DETERMINE THE FREQUENCY INDEPENDENT RECIPROCAL PROPAGATION *     VELOCITY (SLOWNESS) *     ************************************************************	  REAL C,Q,twoQ,twoQsq,twoQsqp1byC	  twoQ=2*Q	  twoQsq=twoQ*twoQ	  twoQsqp1byC=(1+twoQsq)*C	  cmplxslo=cmplx(twoQsq/twoQsqp1byC,TwoQ/twoQsqp1byC)	  RETURN	  END	  	  COMPLEX FUNCTION VERTICALSLO(C,P)	  COMPLEX C,P,T	  T=(C+P)*(C-P)	  VERTICALSLO=csqrt(T)	  IF(AIMAG(VERTICALSLO) .LE. 0.0)THEN 	    VERTICALSLO=-VERTICALSLO	  END IF	  RETURN	  END	        COMPLEX FUNCTION S(OMEGA,OmegaMax)*     ****************************************************************     Fourier transform of Ricker wavelet*     ****************************************************************	  REAL T0	  COMPLEX OMEGA,CI,Z,OmegaMax,Alfa	  CI=(0.0,1.0)	  alfa=0.1*omegamax	  T0=5.0/(ALFA*SQRT(2.0))	  Z=OMEGA*OMEGA/(4.*ALFA*ALFA)	  S=Z*CEXP(-Z+CI*OMEGA*T0)	  RETURN	  END	  	        SUBROUTINE FFT(CX,LX,SIGNI)      COMPLEX CX(LX),CTEMP,CW      J=1      DO 3 I=1,LX      IF(I.GT. J) GO TO 1      CTEMP=CX(J)      CX(J)=CX(I)      CX(I)=CTEMP 1    M=LX/2 2    IF(J.LE.M) GO TO 3      J=J-M      M=M/2      IF(M.GE.1) GO TO 2 3    J=J+M      L=1 4    ISTEP=2*L      DO 5 M=1,L      AA=Pi*SIGNI*FLOAT((M-1))/FLOAT(L)      CW=CMPLX(COS(AA),SIN(AA))      DO 5 I=M,LX,ISTEP      CTEMP=CW*CX(I+L)      CX(I+L)=CX(I)-CTEMP 5    CX(I)=CX(I)+CTEMP      L=ISTEP      IF(L.LT.LX) GO TO 4      RETURN      END      subroutine Kennet_Reflex(nlp1,Nw,Rd11,Rd12,Rd21,Rd22,     &                 Tu11,Tu12,Tu21,Tu22,Ru11,Ru12,     &                 Ru21,Ru22,Td11,Td12,Td21,Td22,inceaea,incebeb,     &                inceaeb,eaea,ebeb,eaeb,ea,eb,incea,inceb,OBreflex)***********************************************************************	  *     compute the ratio of the upgoing to the downgoing wavefield*     of a plane layer stack bounded above by an acoustic halfspace*     using Kennett's Addition Formulae ***********************************************************************      Implicit none      integer  i,j,nlp1,nl,il,Nw,iw,ilp1,NLP1MAX	  PARAMETER(NLP1MAX=5)	  complex  MT11(NLP1MAX),MT12(NLP1MAX),MT21(NLP1MAX),MT22(NLP1MAX)	  complex  TPuPu(nlp1max),TSuPu(nlp1max)      complex  PuPu(NLP1MAX),SuPu(NLP1MAX)	  complex  eaea(nlp1),ebeb(nlp1),eaeb(nlp1),inceaea(nlp1)	  complex  ea(nlp1),eb(nlp1),incea(nlp1),inceb(nlp1)	  complex  Rd11(nlp1),Rd12(nlp1),Rd21(nlp1),Rd22(nlp1)	  complex  Tu11(nlp1),Tu12(nlp1),Tu21(nlp1),Tu22(nlp1)	  complex  Td11(nlp1),Td12(nlp1),Td21(nlp1),Td22(nlp1)	  complex  Ru11(nlp1),Ru12(nlp1),Ru21(nlp1),Ru22(nlp1)	  complex  OBreflex(Nw),incebeb(nlp1),inceaeb(nlp1),PdPd	  complex  RRub11,RRub12,RRub21,RRub22,RRut11,RRut12,RRut21,RRut22	  complex  RRdb11,RRdb12,RRdb21,RRdb22	  complex  C0,C1,U11,U12,U21,U22,InvDet,RR,V11,V12,V21,V22	  parameter(C0=(0.0,0.0),C1=(1.0,0.0))!**********************************************************************	  !     loop over frequency pass-band of source!**********************************************************************	  nl=nlp1-1	  do iw=1,Nw*	  type*,'iw=',iw    *     impose the lower half space radiation condition      MT11(NLP1)=C0	  MT12(NLP1)=C0	  MT21(NLP1)=C0	  MT22(NLP1)=C0      RRdb11=Rd11(nl)	  RRdb12=Rd12(nl)	  RRdb21=Rd21(nl)	  RRdb22=Rd22(nl)*	  type*,'PdPu,SdSu at bottom of layer ',nl,RRdb11,RRdb22*	  pause*     MT=E*RRb*E	  eaea(nl)=eaea(nl)*inceaea(nl)	  ebeb(nl)=ebeb(nl)*incebeb(nl)	  eaeb(nl)=eaeb(nl)*inceaeb(nl)*	  type*,'il,eaea,ebeb=',nl,eaea(nl),ebeb(nl)*	  pause	  MT11(nl)=eaea(nl)*RRdb11	  MT22(nl)=ebeb(nl)*RRdb22	  MT12(nl)=eaeb(nl)*RRdb12	  MT21(nl)=eaeb(nl)*RRdb21*	  type*,'MT11,MT22 il=',nl,MT11(nl),MT22(nl)*	  pause      do il=nl-1,2,-1*     *****************************************************************     use Kennet's recursive algorithm to build the reflectivity from*     the base of the elastic layer stack to the top of layer 2 (i.e.*     just below the ocean bottom)*     *****************************************************************       U=(I-Ru*MT)^(-1)        ilp1=il+1	    U11=C1-Ru21(il)*MT12(ilp1)-Ru22(il)*MT22(ilp1)	    U12=Ru11(il)*MT12(ilp1)+Ru12(il)*MT22(ilp1)	    U21=Ru21(il)*MT11(ilp1)+Ru22(il)*MT21(ilp1)	    U22=C1-Ru11(il)*MT11(ilp1)-Ru12(il)*MT21(ilp1)	    InvDet=C1/(U11*U22-U12*U21)	    U11=U11*InvDet	    U12=U12*InvDet	    U21=U21*InvDet	    U22=U22*InvDet*       V=U*Td        V11=U11*Td11(il)+U12*Td21(il)		V12=U11*Td12(il)+U12*Td22(il)		V21=U21*Td11(il)+U22*Td21(il)		V22=U21*Td12(il)+U22*Td22(il)*       U=MT*V        U11=MT11(ilp1)*V11+MT12(ilp1)*V21		U12=MT11(ilp1)*V12+MT12(ilp1)*V22		U21=MT21(ilp1)*V11+MT22(ilp1)*V21		U22=MT21(ilp1)*V12+MT22(ilp1)*V22*       V=Tu*U        V11=Tu11(il)*U11+Tu12(il)*U21		V12=Tu11(il)*U12+Tu12(il)*U22		V21=Tu21(il)*U11+Tu22(il)*U21		V22=Tu21(il)*U12+Tu22(il)*U22*       RRdb=Rd+V        RRdb11=Rd11(il)+V11		RRdb12=Rd12(il)+V12		RRdb21=Rd21(il)+V21		RRdb22=Rd22(il)+V22*		type*,'RRdb11,RRdb22 il=',il,RRdb11,RRdb22*		pause*       MT=E*RRb*E		eaea(il)=eaea(il)*inceaea(il)		ebeb(il)=ebeb(il)*incebeb(il)		eaeb(il)=eaeb(il)*inceaeb(il)*	  TYPE*,'IL,EAEA(IL),EBEB(IL),EAEB(IL)=',IL,EAEA(IL),EBEB(IL),EAEB(IL)*	  PAUSE		MT11(il)=eaea(il)*RRdb11		MT22(il)=ebeb(il)*RRdb22		MT12(il)=eaeb(il)*RRdb12		MT21(il)=eaeb(il)*RRdb21*		type*,'MT11,MT22 il=',il,MT11(il),MT22(il)*		pause      End Do*     ******************************************************************     generate the reflectivity just above the Ocean Bottom from the*     reflectivity just below the ocean bottom*     ******************************************************************     U=(I-Ru*MT)^(-1)	  U11=c1-Ru21(1)*MT12(2)-Ru22(1)*MT22(2)	  U12=Ru11(1)*MT12(2)+Ru12(1)*MT22(2)	  U21=Ru21(1)*MT11(2)+Ru22(1)*MT21(2)	  U22=c1-Ru11(1)*MT11(2)-Ru12(1)*MT21(2)	  InvDet=C1/(U11*U22-U12*U21)	  U11=U11*InvDet	  U12=U12*InvDet	  U21=U21*InvDet	  U22=U22*InvDet*	  type*,'Ru11(1),Ru22(1)=',Ru11(1),Ru22(1)*	  pause*     RRdb=MT*U		      RRdb11=MT11(2)*U11+MT12(2)*U21      RRdb12=MT11(2)*U12+MT12(2)*U22	  RRdb21=MT21(2)*U11+MT22(2)*U21	  RRdb22=MT21(2)*U12+MT22(2)*U22	  eaea(1)=eaea(1)*inceaea(1)	  RR=Rd11(1)+Tu11(1)*Td11(1)*RRdb11+Tu11(1)*Td21(1)*RRdb12	  RR=RR+Tu12(1)*Td21(1)*RRdb22+Tu12(1)*RRdb21*Td11(1)*	  type*,'reflectivity just above the ocean bottom=',RR*	  pause	  OBreflex(iw)=eaea(1)*RR      type*,'IW=',IW*	  PAUSE!**********************************************************************!     WITH A DOWNWARD SWEEP FROM THE OCEAN BOTTOM CALCULATE  PuPu & RRu!***********************************************************************     NO FREE SURFACE EFFECTS INCLUDED      RRut11=Ru11(1)	  RRut12=Ru12(1)	  RRut21=Ru21(1)	  RRut22=Ru22(1)*	  type*,'il,RRut11=',2,Ru11(1)*	  pause*     TTu=Tu*     upwards transmission coefficients from the top of layer 2      ea(1)=ea(1)*incea(1)*      PuPu(2)=EA(1)*Tu11(1)*      SuPu(2)=EB(1)*Tu12(1)      PuPu(2)=Tu11(1)      SuPu(2)=Tu12(1)*     U=(I-MT*RRut)^(-1)	  U11=C1-MT21(2)*RRut12-MT22(2)*RRut22	  U12=MT11(2)*RRut12+MT12(2)*RRut22	  U21=MT21(2)*RRut11+MT22(2)*RRut21	  U22=C1-MT11(2)*RRut11-MT12(2)*RRut21	  InvDet=C1/(U11*U22-U12*U21)	  U11=U11*InvDet	  U12=U12*InvDet	  U21=U21*InvDet	  U22=U22*InvDet*     TTu=Tu*U      TPuPu(2)=PuPu(2)*U11+SuPu(2)*U21	  TSuPu(2)=PuPu(2)*U12+SuPu(2)*U22*      type*,'TPuPu,TSuPu from the top of layer ',2,TPuPu(2),TSuPu(2)*	  pause	  do il=2,nl        ilp1=il+1	    RRub11=eaea(il)*RRut11		RRub12=eaeb(il)*RRut12		RRub21=eaeb(il)*RRut21		RRub22=ebeb(il)*RRut22*		type*,'PuPd,SuSd ,EAEA at bottom of layer=',il,RRub11,RRub22,EAEA(IL)*		pause*       U=(I-Rd*RRub)^(-1)	    U11=C1-Rd21(il)*RRub12-Rd22(il)*RRub22	    U12=Rd11(il)*RRub12+Rd12(il)*RRub22	    U21=Rd21(il)*RRub11+Rd22(il)*RRub21	    U22=C1-Rd11(il)*RRub11-Rd12(il)*RRub21	    InvDet=C1/(U11*U22-U12*U21)	    U11=U11*InvDet	    U12=U12*InvDet	    U21=U21*InvDet	    U22=U22*InvDet*       V=U*Tu        V11=U11*Tu11(il)+U12*Tu21(il)		V12=U11*Tu12(il)+U12*Tu22(il)		V21=U21*Tu11(il)+U22*Tu21(il)		V22=U21*Tu12(il)+U22*Tu22(il)*       calculate PuPu & SuPu from top of layer ilp1    	ea(il)=ea(il)*incea(il)        eb(il)=eb(il)*inceb(il)        PuPu(ilp1)=PuPu(il)*ea(il)*V11+SuPu(il)*eb(il)*V21		SuPu(ilp1)=PuPu(il)*ea(il)*V12+SuPu(il)*eb(il)*V22*	    type*,'PuPu,SuPu at top of lower ilp1=',ilp1,PuPu(ilp1),SuPu(ilp1)*       U=RRub*V        U11=RRub11*V11+RRub12*V21		U12=RRub11*V12+RRub12*V22		U21=RRub21*V11+RRub22*V21		U22=RRub21*V12+RRub22*V22*       V=Td*U        V11=Td11(il)*U11+Td12(il)*U21		V12=Td11(il)*U12+Td12(il)*U22		V21=Td21(il)*U11+Td22(il)*U21		V22=Td21(il)*U12+Td22(il)*U22*       RRut=Ru+V        RRut11=Ru11(il)+V11		RRut12=Ru12(il)+V12		RRut21=Ru21(il)+V21		RRut22=Ru22(il)+V22	*		type*,'PuPd,SuSd at top of layer=',il+1,RRut11,RRut22*       U=(I-MT*RRut)^(-1)	    U11=C1-MT21(ilp1)*RRut12-MT22(ilp1)*RRut22	    U12=MT11(ilp1)*RRut12+MT12(ilp1)*RRut22	    U21=MT21(ilp1)*RRut11+MT22(ilp1)*RRut21	    U22=C1-MT11(ilp1)*RRut11-MT12(ilp1)*RRut21	    InvDet=C1/(U11*U22-U12*U21)	    U11=U11*InvDet	    U12=U12*InvDet	    U21=U21*InvDet	    U22=U22*InvDet*       TTu=Tu*U        TPuPu(ilp1)=PuPu(ilp1)*U11+SuPu(ilp1)*U21		TSuPu(ilp1)=PuPu(ilp1)*U12+SuPu(ilp1)*U22*        type*,'TPuPu,TSuPu from the top of layer ',ilp1,TPuPu(ilp1),TSuPu(ilp1)*		pause		end do	  end do!**********************************************************************!     END FREQUENCY LOOP!**********************************************************************	  return	  end	  	  Subroutine  ScatMat(p,eta1,neta1,rho1,beta1,eta2,neta2,rho2,beta2,     &                     Rd11,Rd12,Rd21,Rd22,Tu11,Tu12,Tu21,Tu22,     &                     Td11,Td12,Td21,Td22,Ru11,Ru12,Ru21,Ru22)*     *********************************************************************     modified interfacial scattering matrices (see Aki&Richards pp149-51)*     ********************************************************************	  REAL RHO1,RHO2,rtrho1,rtrho2,p	  COMPLEX ETA1,NETA1,ETA2,NETA2,BETA1,BETA2,PSQ,CRHO1,CRHO2,DRHO,DMU	  COMPLEX rteta1,rteta2,rtneta1,rtneta2,Ci,m2Ci,Rd11,Rd12,Rd21,Rd22      COMPLEX Tu11,Tu12,Tu21,Tu22,Td11,Td12,Td21,Td22,Ru11,Ru12,Ru21,Ru22	  COMPLEX PSQD,a,b,c,d,Det,E,F,G,H,Q,R,S,T,U,V,rtza1,rtza2,rtzb1,rtzb2	  Ci=(0.0,1.0)	  m2Ci=(0.0,-2.0)	  rtrho1=sqrt(rho1)	  rtrho2=sqrt(rho2)	  rteta1=csqrt(eta1)	  rteta2=csqrt(eta2)	  rtneta1=csqrt(neta1)	  rtneta2=csqrt(neta2)	  rtza1=rteta1*rtrho1	  rtza2=rteta2*rtrho2	  rtzb1=rtneta1*rtrho1	  rtzb2=rtneta2*rtrho2	  psq=p*p	  crho1=cmplx(rho1,0.0)	  crho2=cmplx(rho2,0.0)	  drho=crho2-crho1	  dmu=crho2*beta2*beta2-crho1*beta1*beta1	  d=2.0*dmu	  psqd=psq*d	  a=drho-psqd	  b=crho2-psqd	  c=crho1+psqd	  E=(b*eta1+c*eta2)	  F=(b*neta1+c*neta2)	  G=(a-d*eta1*neta2)	  H=(a-d*eta2*neta1)	  Det=E*F+G*H*psq	  E=E/Det	  F=F/Det	  G=G/Det	  H=H/Det	  Q=(B*ETA1-C*ETA2)*F	  R=(a+d*eta1*neta2)*H*psq	  S=(a*b+c*d*eta2*neta2)*p/Det	  T=(b*neta1-c*neta2)*E	  U=(a+d*eta2*neta1)*G*psq	  V=(a*c+b*d*eta1*neta1)*p/Det	  Rd11=Q-R	  Rd21=m2ci*rteta1*rtneta1*S	  Rd12=Rd21	  Rd22=T-U	  Td11=2*rtza1*rtza2*F	  Td21=m2ci*rtza1*rtzb2*H*p	  Td12=m2ci*rtzb1*rtza2*G*p	  Td22=2*rtzb1*rtzb2*E	  Tu11=Td11	  Tu21=Td12	  Tu12=Td21	  Tu22=Td22	  Ru11=-(Q+U)	  Ru21=m2ci*rteta2*rtneta2*V	  Ru12=Ru21	  Ru22=-(T+R)	  	  return	  end	  	  	  SUBROUTINE OBSMat(P,ETA1,RHO1,ETA2,NETA2,RHO2,BETA2,     +           PdPu,PdPd,PdSd,PuPu,PuPd,PuSd,SuPu,SuPd,SuSd)*     calculate scattering matrix of the sea floor      Implicit none	  REAL RHO1,RHO2,rtrho1,rtrho2,p,PSQ	  COMPLEX ETA1,ETA2,NETA2,BETA2,CRHO1,CRHO2	  COMPLEX T1,T2,T4,T5,T6,a,b,c,d,Det,drho,dmu,psqd	  complex rteta1,rteta2,rtneta2,Ci,mCi,E,F,G,H,rtza1,rtza2,rtzb2	  COMPLEX PdPu,PdPd,PdSd,PuPu,PuPd,PuSd,SuPu,SuPd,SuSd	  Ci=(0.0,1.0)	  mCi=(0.0,-1.0)	  rtrho1=sqrt(rho1)	  rtrho2=sqrt(rho2)	  rteta1=csqrt(eta1)	  rteta2=csqrt(eta2)	  rtneta2=csqrt(neta2)	  rtza1=rtrho1*rteta1	  rtza2=rtrho2*rteta2	  rtzb2=rtrho2*rtneta2	  psq=p*p	  crho1=cmplx(rho1,0.0)	  crho2=cmplx(rho2,0.0)	  drho=crho2-crho1	  dmu=crho2*beta2*beta2	  d=2.0*dmu	  psqd=psq*d	  a=drho-psqd	  b=crho2-psqd	  c=crho1+psqd	  E=b*eta1+c*eta2	  F=b	  G=a-d*eta1*neta2	  H=-d*eta2	  Det=E*F+G*H*psq      E=E/Det	  F=F/Det	  G=G/Det	  H=H/Det	  T1=(b*eta1-c*eta2)*F	  T2=(a+d*eta1*neta2)*H*psq	  T4=b*E	  T5=d*eta2*G*psq	  T6=b*d*eta1*p/Det	  PdPu=(T1-T2)	  PdPd=2.0*rtza1*rtza2*F	  PdSd=2.0*mCi*rtza1*rtzb2*H*p	  PuPu=PdPd	  SuPu=PdSd	  PuPd=-(T1+T5)	  PuSd=2*mci*rteta2*rtneta2*T6	  SuPd=PuSd	  SuSd=-(T2+T4)	  return	  end		  	  